parameters.jsCode:
const interview = $input.first().json;

const interviewerList = interview.interviewer_names && interview.interviewer_names.length > 0
  ? interview.interviewer_names.join(', ')
  : 'the interviewer(s)';

const prompt = `Write a professional thank-you email for a job interview.

Context:
- Company: ${interview.company_name}
- Role: ${interview.role_title}
- Interview type: ${(interview.interview_format || '').replace(/_/g, ' ')}
- Track: ${interview.interview_track}
- Stage: ${(interview.interview_stage || 'not specified').replace(/_/g, ' ')}
- Interviewer(s): ${interviewerList}
- The candidate is a PhD + MBA professional with 18 years of HR/L&D experience

Requirements:
- Professional UK English tone
- Brief (150-200 words)
- Reference something specific about the role or company (use a [ADD YOUR OWN OBSERVATION HERE] placeholder for a personal touch the candidate should add)
- Express continued interest
- Mention a specific strength relevant to the role
- Do NOT be overly effusive or sycophantic
- Include a [ADD YOUR OWN OBSERVATION HERE] placeholder where the candidate should insert a specific moment or topic from the interview
- End with a forward-looking statement

Generate ONLY the email body (no subject line, no greeting format instructions). Start with "Dear [interviewer name],"`;

return {
  interview_id: interview.interview_id,
  company_name: interview.company_name,
  role_title: interview.role_title,
  interview_track: interview.interview_track,
  interviewer_names: interview.interviewer_names,
  prompt: prompt
};

